  (NULL, 'ログハウス推進部', NULL, '自動車の運転', 'ログハウス建築予定地への移動時', '交通事故による怪我、骨折、死亡', E'①アルコールチェックの実施\n②十分な休憩、睡眠\n③交通法規の順守（安全速度、急発進・急停車をしない）\n④体調確認、声掛け', 'D/D/D/D', 1, 3, true, 'risk', NULL),
  (NULL, 'パトロール部', NULL, '自動車の運転', '場所によって、島内巡回時に洪水や土砂崩れ', '自然災害に被災、怪我', E'①天候・気象の事前確認\n②危険な兆候の察知', 'D/D', 1, 3, false, 'risk', NULL),
  (NULL, 'パトロール部', NULL, '石、倒木', '担当者が除去中', '交通事故による怪我、死亡', E'①バリケードの設置\n②二人作業で周囲への注意', 'C/D', 1, 3, false, 'risk', NULL),
  (NULL, 'パトロール部', NULL, '動物', '担当者が除去中', '動物からの噛まれる/突進などの怪我', E'①保護具使用（専用手袋）、直接触れない\n②回収した動物は冷凍保管（振興局）\n③生きている場合は近づかない、逃がす', 'E/C/D', 1, 2, false, 'risk', NULL),
  (NULL, '会社全体', NULL, 'くるみんプラス認定', '会社として「くるみんプラス認定」の取り組み時', '従業員満足度向上、ストレス軽減', E'①女性不妊治療に伴う休暇取得\n②両立支援として所定労働時間を5時間とする\n③時短勤務\n④男性育児休暇の取得奨励', 'D/D/D/D', 3, 1, true, 'opportunity', NULL),
  (NULL, '会社全体', NULL, '社員コミュニケーション', '新年会等', '従業員満足度向上、ストレス軽減', E'①社員間の親睦を深める新年会等の実施', 'D', 3, 1, true, 'opportunity', NULL),
  (NULL, '会社全体', NULL, 'Nぴか認定', '会社として「Nぴか認定」の取り組み時', '従業員満足度向上、ストレス軽減', E'①従業員の健康づくりの為のラジオ体操\n②ストレスチェック\n③多様な働き方推進の為のテレワーク推進（PC貸与し、在宅勤務）', 'D/D/D', 3, 1, true, 'opportunity', NULL);
