  (NULL, '工事部', '仮設工事', '高所作業', '足場・屋根上・足場板上での作業時', '墜落による重傷・死亡', E'①安全帯（フルハーネス）の着用\n②手すり・幅木の設置\n③脚立ではなく立馬等の使用を推奨', 'E/C', 1, 3, false, 'risk', NULL),
  (NULL, '工事部', '仮設工事', '資材', '高所からの資材落下、強風下の飛来物', '落下物による頭部負傷・骨折', E'①落下防止ネット・養生の設置\n②風速監視', 'C/D', 1, 2, false, 'risk', NULL),
